class Solution {
public:
    int canCompleteCircuit(vector<int>& gas, vector<int>& cost) {
        int n = cost.size();
        int indexOfMax = 0;
        int min_cost = 0;

        for(int i = 0; i < n; i++){
            int temp = gas[i] - cost[i];
            if(min_cost < temp){
                indexOfMax = i;
                min_cost = temp;
            }

        }

        int total_cost = gas[indexOfMax];

        // Loop from start_index to the end of the array
        for (int i = indexOfMax+1; i < gas.size(); ++i) {
            total_cost += gas[i] - cost[i];
            if(total_cost < 0){
                return -1;
            }
        }

        // Loop from 0 to start_index - 1
        for (int i = 0; i < indexOfMax; ++i) {
            total_cost += gas[i] - cost[i];
            if(total_cost < 0){
                return -1;
            }
        }
        total_cost -= cost[indexOfMax];
            if(total_cost < 0){
                return -1;
            }

        return indexOfMax;
    }
};

class Solution {
public:
    int canCompleteCircuit(vector<int>& gas, vector<int>& cost) {
        int n = cost.size();
        int minVal = 0;
        int minIndex = -1;
        int total_val = 0;

        for(int i = 0; i < n; i++){
            int temp = gas[i] - cost[i];
            total_val += temp;
            if(total_val < minVal){
                minVal = total_val;
                minIndex = i;
            }
        }

        if(total_val < 0)
            return -1;

        return (minIndex + 1) % n;;
    }
};
